getClientKey(req) {
  // Use combination of IP and User-Agent for better identification
  const ip = req.ip || req.connection.remoteAddress;
  const userAgent = req.get('User-Agent') || 'unknown';
  const hash = require('crypto')
    .createHash('sha256')
    .update(`${ip}:${userAgent}`)
    .digest('hex')
    .substring(0, 16);

  return `auth:${hash}`;
}

