getObjectDepth(obj) {
  if (typeof obj !== 'object' || obj === null) {
    return 0;
  }

  let maxDepth = 0;
  for (const key in obj) {
    if (obj.hasOwnProperty(key)) {
      const depth = this.getObjectDepth(obj[key]);
      maxDepth = Math.max(maxDepth, depth);
    }
  }

  return maxDepth + 1;
}
